n0:createOraclePackageSpec.n0:source:
CREATE OR REPLACE EDITIONABLE PACKAGE "%USER_NAME%"."MAXPRINT_PLSQL_API_V2" AS
    v_url              varchar2(100)   := 'https://appv2.maxprint.io/api/v1';
    v_report_context   varchar2(100)   := '/report/run/template/';
    v_app_id           varchar2(50)    := v('APP_ID');
    v_workspace_id     varchar2(50)    := v('WORKSPACE_ID');
    v_timeout          number          := 6000;
    v_debug            boolean         := false;
    v_development_mode boolean         := false;

    FUNCTION maxprint_api_call(
        p_url                  in varchar2,
        p_api_key              in varchar2,
        p_data                 in clob,
        p_output_type          in varchar2,
        p_template             in clob default null,
        p_template_id          in varchar2 default null,
        p_wallet_path          in varchar2 default null,
        p_wallet_password      in varchar2 default null,
        p_timeout              in number default v_timeout,
        p_debug                in boolean default v_debug,
        p_development_mode     in boolean default v_development_mode
    ) RETURN clob ;

    PROCEDURE Print_Payload(P_Text in out nocopy clob);

    PROCEDURE Dbms_Print_Payload(P_Text in out nocopy clob);

    FUNCTION GET_APEX_DIRECTORY_CONTENT_JSON(P_Directory IN VARCHAR2, P_File_Name IN VARCHAR2, P_App IN VARCHAR2 DEFAULT v_app_id, P_Workspace IN VARCHAR2 DEFAULT v_workspace_id) RETURN CLOB;

    FUNCTION GET_JSON_FROM_PLSQL(pl_code in clob, p_datasoure_type varchar2 default 'FRS') RETURN clob;

    FUNCTION GET_JSON_FROM_SQL(p_sql IN CLOB, p_sql_type VARCHAR2, p_query_master_cols VARCHAR2 DEFAULT NULL) RETURN CLOB;

    FUNCTION get_json_from_refcursor(p_refcursor in SYS_REFCURSOR ) RETURN CLOB;

    FUNCTION maxprint_generate_report_clob(
        p_api_key              in varchar2,
        p_data                 in clob,
        p_output_type          in varchar2,
        p_template             in clob default null,
        p_template_id          in varchar2 default null,
        p_wallet_path          in varchar2 default null,
        p_wallet_password      in varchar2 default null,
        p_timeout              in number   default  v_timeout,
        p_url                  in varchar2 default v_url||v_report_context,
        p_debug                in boolean default v_debug,
        p_development_mode     in boolean default v_development_mode                                                       
    ) RETURN clob;

    FUNCTION maxprint_generate_report_blob( 
        p_api_key              in varchar2,
        p_data                 in clob,
        p_output_type          in varchar2,
        p_template             in clob default null,
        p_template_id          in varchar2 default null,
        p_wallet_path          in varchar2 default null,
        p_wallet_password      in varchar2 default null,
        p_timeout              in number   default  v_timeout,
        p_url                  in varchar2 default v_url||v_report_context,
        p_debug                in boolean default v_debug,
        p_development_mode     in boolean default v_development_mode
    ) RETURN blob; 
end "MAXPRINT_PLSQL_API_V2";
/
